&lt;td&gt;watch 支持&lt;/td&gt;
&lt;td&gt;支持 long polling / 大部分增量&lt;/td&gt;
&lt;td&gt;全量 / 支持 long polling&lt;/td&gt;
&lt;td&gt;支持&lt;/td&gt;
&lt;td&gt;支持 long polling&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;自身监控&lt;/td&gt;
&lt;td&gt;metrics&lt;/td&gt;
&lt;td&gt;metrics&lt;/td&gt;
&lt;td&gt;—&lt;/td&gt;
&lt;td&gt;metrics&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;安全&lt;/td&gt;
